class AnimationController{constructor(){this.timeline=gsap.timeline();this.scrollTriggers=[];this.isTransitioning=false;this.currentPage=null;this.animationDuration=.8;this.initialized=false}init(){if(this.initialized)return;gsap.registerPlugin(ScrollTrigger);window.addEventListener("themeChanged",e=>{this.onThemeChange(e.detail)});this.setupIntersectionObserver();this.currentPage=this.detectCurrentPage();this.setupNavigationHandlers();this.initialized=true;console.log("🎬 Animation Controller initialized")}detectCurrentPage(){const path=window.location.pathname;const filename=path.split("/").pop()||"index.html";let pageName="home";if(filename.includes("journey"))pageName="journey";else if(filename.includes("creations"))pageName="creations";else if(filename.includes("odyssey"))pageName="odyssey";else if(filename.includes("connect"))pageName="connect";return pageName}setupNavigationHandlers(){document.addEventListener("click",e=>{const link=e.target.closest("a[href]");if(!link)return;const href=link.getAttribute("href");if(this.isInternalPageLink(href)){e.preventDefault();this.navigateToPage(href)}})}isInternalPageLink(href){const internalPages=["index.html","/","journey.html","creations.html","odyssey.html","connect.html"];const baseHref=href.split("#")[0].split("?")[0];return internalPages.some(page=>baseHref.includes(page)||baseHref==="")}navigateToPage(href){if(this.isTransitioning)return;this.isTransitioning=true;const targetPage=this.getPageNameFromHref(href);const transitionTL=gsap.timeline({onComplete:()=>{window.location.href=href}});transitionTL.to(document.body,{opacity:0,duration:this.animationDuration*.6,ease:"power2.inOut"},0);transitionTL.to(document.documentElement,{"--accent-saturation":"120%",duration:this.animationDuration*.4,ease:"power2.inOut"},0);transitionTL.to(document.documentElement,{"--accent-saturation":"100%",duration:this.animationDuration*.2,ease:"power2.inOut"},this.animationDuration*.4)}getPageNameFromHref(href){const cleanHref=href.split("#")[0].split("?")[0];if(cleanHref.includes("journey"))return"journey";if(cleanHref.includes("creations"))return"creations";if(cleanHref.includes("odyssey"))return"odyssey";if(cleanHref.includes("connect"))return"connect";return"home"}onThemeChange(detail){const{theme:theme,pageName:pageName}=detail;this.playPageEntranceAnimation(pageName,theme)}playPageEntranceAnimation(pageName,theme){const entranceTL=gsap.timeline();entranceTL.to(document.body,{opacity:1,duration:this.animationDuration*.5,ease:"power2.out"},0);const animationClass=this.getEntranceAnimationClass(pageName);const elements=document.querySelectorAll(`.${animationClass}`);if(elements.length>0){elements.forEach((el,index)=>{entranceTL.to(el,{duration:.1,onStart:()=>{el.classList.add(animationClass)}},index*.1)})}const staggerItems=document.querySelectorAll(".stagger-item");if(staggerItems.length>0){entranceTL.to(staggerItems,{opacity:1,y:0,duration:.6,stagger:.1,ease:"power2.out"},.2)}}getEntranceAnimationClass(pageName){const animationMap={home:"animate-kaleidoscope",journey:"animate-timeline",creations:"animate-drift-rotate",odyssey:"animate-unfold",connect:"animate-network"};return animationMap[pageName]||"fade-in"}setupIntersectionObserver(){const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){this.playScrollAnimation(entry.target)}})},{threshold:.1,rootMargin:"0px 0px -100px 0px"});document.querySelectorAll(".animate-on-scroll").forEach(el=>{observer.observe(el)});this.scrollObserver=observer}playScrollAnimation(element){if(element.classList.contains("animated"))return;element.classList.add("animated");if(element.classList.contains("stagger-item")){gsap.to(element,{opacity:1,y:0,duration:.8,ease:"power2.out"})}else{gsap.to(element,{opacity:1,y:0,duration:.8,ease:"power2.out"})}}createParallax(element,speed=.5){ScrollTrigger.create({trigger:element,onUpdate:self=>{gsap.to(element,{y:self.getVelocity()*speed,overwrite:"auto"})}})}staggerAnimate(selector,animationProps={},staggerAmount=.1){const elements=typeof selector==="string"?document.querySelectorAll(selector):selector;return gsap.to(elements,{...animationProps,stagger:staggerAmount,duration:animationProps.duration||.6,ease:animationProps.ease||"power2.out"})}revealElement(element,direction="left",duration=.8){const clipPaths={left:["inset(0 100% 0 0)","inset(0 0 0 0)"],right:["inset(0 0 0 100%)","inset(0 0 0 0)"],top:["inset(100% 0 0 0)","inset(0 0 0 0)"],bottom:["inset(0 0 100% 0)","inset(0 0 0 0)"]};gsap.fromTo(element,{clipPath:clipPaths[direction][0]},{clipPath:clipPaths[direction][1],duration:duration,ease:"power2.inOut"})}destroy(){if(this.scrollObserver){this.scrollObserver.disconnect()}this.timeline.kill();this.scrollTriggers.forEach(trigger=>trigger.kill())}}const animationController=new AnimationController;if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",()=>{animationController.init()})}else{animationController.init()}if(typeof module!=="undefined"&&module.exports){module.exports=AnimationController}